statements.select:
       /*'[' + CJOB_NO + ']' + ,CJOB_TYPE*/
SELECT CJOB_NO CODE ,CJOB_NAME TEXT 
FROM SHARE_CJOB
WHERE CJOB_NO IS NOT NULL AND JOB_NO IS NULL AND CYEARS='2016' 
ORDER BY CJOB_NO      
/*AND CJOB_TYPE=#CJOB_TYPE# */

       /*CJOB_NO + '.' + JOB_NO + ,CJOB_TYPE*/ 
SELECT CAST(CJOB_UNKEY AS varchar) CODE ,CJOB_NAME TEXT 
FROM SHARE_CJOB 
WHERE CJOB_NO IS NOT NULL AND JOB_NO IS NOT NULL AND CYEARS='2016' 
ORDER BY CJOB_NO ,JOB_NO
/*AND CJOB_NO=#CJOB_NO# */
